function makePage({ slug, category, title, h1, h1Span, hero, metaDescription, service, keywords, when, callout, quickTitle, quick, faqs }) {
  const t = templates[category];
  return {
    slug,
    category,
    title: title || `${titleFromSlug(slug)} | WorkIndex`,
    h1: h1 || titleFromSlug(slug),
    h1Span: h1Span || 'Compare Experts on WorkIndex',
    hero,
    metaDescription,
    service,
    keywords,
    eyebrow: category === 'itr' ? 'Income Tax' : category === 'gst' ? 'GST Services' : category === 'audit' ? 'Audit and Compliance' : category === 'accounting' ? 'Accounting Services' : 'Web Development',
    stats: t.stats,
    quickTitle,
    quick,
    callout,
    when,
    documents: t.documents,
    process: t.process,
    mistakes: t.mistakes,
    request: t.request,
    hire: t.hire,
    deepDive: t.deepDive,
    pricing: t.pricing,
    faqs,
    related: related[category],
    references: refs[category]
  };
}

